INSERT INTO projects (id, sort_order, name, owner_team, description, status, business_background, data_source, created_at) VALUES ('PROJ-001', 1, '自动驾驶', 'AI投研业务数据团队', '围绕行业专题承接需求定义、宽表生成和任务执行。', 'active', '聚焦自动驾驶运营效率与安全指标，面向月度更新与专题分析。', '{"search": {"engines": ["bing", "volcano"], "sites": ["site:waymo.com", "site:ponyai.com", "site:dmv.ca.gov"], "sitePolicy": "preferred"}, "knowledgeBases": ["kb_autodrive_industry"], "fixedUrls": ["https://waymo.com/safety/", "https://pony.ai/"]}', NOW());
INSERT INTO projects (id, sort_order, name, owner_team, description, status, business_background, data_source, created_at) VALUES ('PROJ-002', 2, '创新药', 'AI投研业务数据团队', '围绕临床疗效与安全性构建结构化生产链路。', 'active', '聚焦肿瘤药物临床疗效、安全性与监管披露的结构化生产。', '{"search": {"engines": ["volcano"], "sites": ["site:clinicaltrials.gov", "site:fda.gov", "site:asco.org"], "sitePolicy": "whitelist"}, "knowledgeBases": ["kb_pharma_reports"], "fixedUrls": ["https://clinicaltrials.gov/", "https://www.fda.gov/"]}', NOW());
INSERT INTO requirements (id, sort_order, project_id, title, phase, parent_requirement_id, schema_locked, status, owner, assignee, business_goal, background_knowledge, business_boundary, delivery_scope, data_update_enabled, data_update_mode, processing_rule_drafts, collection_policy, created_at, updated_at) VALUES ('REQ-2026-001', 1, 'PROJ-001', '自动驾驶运营快照采集', 'production', NULL, 0, 'scoping', '业务-张宁', '算法-陈飞', '先把自动驾驶运营快照宽表稳定下来，再按全量快照生成记录、任务组与采集任务。', '当前需求按运营商维度采集全量快照，不按业务日期做增量拆分。', NULL, NULL, 0, NULL, '[]', '{"search_engines": ["bing", "volcano"], "preferred_sites": ["site:didiglobal.com", "site:ruqi-mobility.com", "site:caocao.com", "site:pony.ai"], "site_policy": "preferred", "knowledge_bases": ["kb_autodrive_industry"], "fixed_urls": ["https://www.didiglobal.com/", "https://www.ruqi-mobility.com/", "https://www.caocao.com/", "https://pony.ai/"], "null_policy": "未提及填 NULL，不允许把缺失写成 0。", "source_priority": "企业官网 > 行业统计 > 券商研报 > 媒体。", "value_format": "数值列与单位分离存储。"}', NOW(), NOW());
INSERT INTO requirements (id, sort_order, project_id, title, phase, parent_requirement_id, schema_locked, status, owner, assignee, business_goal, background_knowledge, business_boundary, delivery_scope, data_update_enabled, data_update_mode, processing_rule_drafts, collection_policy, created_at, updated_at) VALUES ('REQ-2026-004', 2, 'PROJ-001', '自动驾驶安全月度采集', 'production', NULL, 1, 'running', '业务-张宁', '算法-陈飞', '沿用已稳定的安全宽表定义，按月持续回填历史月份并为未来月份预铺宽表行。', 'MPI 接管里程与事故率都必须保持百万公里归一口径，历史业务月份优先按补采方式回填。', NULL, NULL, 1, 'incremental', '[]', '{"search_engines": ["bing", "volcano"], "preferred_sites": ["site:waymo.com", "site:ponyai.com", "site:dmv.ca.gov"], "site_policy": "preferred", "knowledge_bases": ["kb_autodrive_industry"], "fixed_urls": ["https://waymo.com/safety/", "https://pony.ai/", "https://dmv.ca.gov/"], "null_policy": "未提及填 NULL，不允许把缺失写成 0。", "source_priority": "监管公告 > 企业官网 > 券商研报 > 媒体。", "value_format": "日期统一为 YYYY-MM，数值列与单位分离存储。"}', NOW(), NOW());
INSERT INTO requirements (id, sort_order, project_id, title, phase, parent_requirement_id, schema_locked, status, owner, assignee, business_goal, background_knowledge, business_boundary, delivery_scope, data_update_enabled, data_update_mode, processing_rule_drafts, collection_policy, created_at, updated_at) VALUES ('REQ-2026-002', 3, 'PROJ-002', 'ADC 三期疗效采集', 'production', NULL, 1, 'stabilized', '业务-李珂', '算法-许越', '先把临床疗效与安全性的宽表 Schema、指标组和业务日期范围稳定下来。', '需要按药物和适应症固定主维度，避免跨队列比较。', NULL, NULL, 0, NULL, '[]', '{"search_engines": ["volcano"], "preferred_sites": ["site:clinicaltrials.gov", "site:fda.gov", "site:asco.org"], "site_policy": "whitelist", "knowledge_bases": ["kb_pharma_reports"], "fixed_urls": [], "null_policy": "无法验证时填 NULL，并保留来源解释。", "source_priority": "监管网站 > 学术会议摘要 > 企业公告。", "value_format": "ORR/TEAE 按百分比存储，PFS 统一按月。"}', NOW(), NOW());
INSERT INTO requirements (id, sort_order, project_id, title, phase, parent_requirement_id, schema_locked, status, owner, assignee, business_goal, background_knowledge, business_boundary, delivery_scope, data_update_enabled, data_update_mode, processing_rule_drafts, collection_policy, created_at, updated_at) VALUES ('REQ-2026-003', 4, 'PROJ-002', 'ADC 三期疗效采集', 'production', 'REQ-2026-002', 1, 'running', '业务-李珂', '算法-许越', '沿用已稳定的临床宽表定义，在不改 Schema 的前提下扩展药物与业务日期范围并持续执行。', '正式需求不允许修改 Schema，只允许扩展药物、适应症和业务日期范围，并调整指标组、调度和补采。', NULL, NULL, 1, 'incremental', '[]', '{"search_engines": ["volcano"], "preferred_sites": ["site:clinicaltrials.gov", "site:fda.gov", "site:asco.org"], "site_policy": "whitelist", "knowledge_bases": ["kb_pharma_reports"], "fixed_urls": [], "null_policy": "无法验证时填 NULL，并保留来源解释。", "source_priority": "监管网站 > 学术会议摘要 > 企业公告。", "value_format": "ORR/TEAE 按百分比存储，PFS 统一按月。"}', NOW(), NOW());
