is_business_date": false}, {"key": "row_status", "name": "行状态", "role": "system", "data_type": "string", "description": "系统维护的宽表行状态。", "required": true, "unit": null, "is_business_date": false}, {"key": "last_task_id", "name": "最近任务ID", "role": "system", "data_type": "string", "description": "最近一次触发采集的任务ID。", "required": true, "unit": null, "is_business_date": false}, {"key": "updated_at", "name": "更新时间", "role": "system", "data_type": "datetime", "description": "最近一次写回宽表的时间。", "required": true, "unit": null, "is_business_date": false}]}', '{"business_date": null, "dimensions": [{"column_key": "company", "values": ["Waymo", "滴滴全球", "如祺出行", "曹操出行", "小马智行"]}]}', '[{"id": "IG-AD-OPS-CORE", "name": "运营快照指标组", "indicator_keys": ["order_volume", "fleet_size", "operating_mileage", "order_price", "order_count"], "execution_mode": "agent", "default_agent": "ops-agent", "prompt_template": "优先采集官网披露的运营快照口径，并保持不同运营商之间的统计口径一致。", "prompt_config": null, "description": "", "priority": 10, "timeout_seconds": 600, "source_preference": ["企业官网", "行业统计"]}]', '[{"id": "SR-AD-OPS-MONTHLY", "frequency": "monthly", "trigger_time": "09:00", "auto_retry_limit": 2, "enabled": true}]', 'none', 'full_snapshot', 'active', 5, NOW(), NOW());
